Operator and submission constraints:

Optimize Y = W @ X + A @ (B.T @ X). W and X are d x d, A and B are d x 16, d is runtime-selected in [3584, 4608], all tensors are CUDA float32, and the exported function is torch::Tensor forward(torch::Tensor W, torch::Tensor X, torch::Tensor A, torch::Tensor B).

Candidate metadata:

{
  "block_size": 256,
  "family": "cublas_plus_custom_rank16_update",
  "id": 1,
  "llm_generated": true,
  "name": "pure_cublas_three_sgemm_3sgemm_style",
  "parent": 0,
  "shape_dispatch": false,
  "strategy": "Replace ATen matmul/transpose/add path with three direct cuBLAS SGEMMs, avoid B.T materialization and input copies, and accumulate the rank-16 update into Y with beta=1. This should reduce framework overhead while keeping cuBLAS for the dominant W@X term.",
  "use_fast_math": false,
  "vector_width": 1
}

Candidate source code:

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <c10/cuda/CUDAGuard.h>
#include <cublas_v2.h>

torch::Tensor forward(torch::Tensor W, torch::Tensor X, torch::Tensor A, torch::Tensor B) {
    c10::cuda::CUDAGuard device_guard(W.device());

    const int64_t d64 = W.size(0);
    const int d = static_cast<int>(d64);

    auto Y = torch::empty_like(W);
    auto U = torch::empty({d64, 16}, W.options());

    cublasHandle_t handle = at::cuda::getCurrentCUDABlasHandle();

    const float alpha = 1.0f;
    const float beta0 = 0.0f;
    const float beta1 = 1.0f;

    // Y_col = X_col * W_col
    cublasSgemm(handle,
                CUBLAS_OP_N, CUBLAS_OP_N,
                d, d, d,
                &alpha,
                X.data_ptr<float>(), d,
                W.data_ptr<float>(), d,
                &beta0,
                Y.data_ptr<float>(), d);

    // U_col[d,16] = X_col * B_col^T
    cublasSgemm(handle,
                CUBLAS_OP_N, CUBLAS_OP_T,
                d, 16, d,
                &alpha,
                X.data_ptr<float>(), d,
                B.data_ptr<float>(), 16,
                &beta0,
                U.data_ptr<float>(), d);

    // Y_col += U_col * A_col
    cublasSgemm(handle,
                CUBLAS_OP_N, CUBLAS_OP_N,
                d, d, 16,
                &alpha,
                U.data_ptr<float>(), d,
                A.data_ptr<float>(), 16,
                &beta1,
                Y.data_ptr<float>(), d);

    return Y;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("forward", &forward, "LoRA forward");
}

Additional review emphasis:

- For a pure cuBLAS three-SGEMM candidate, focus on cuBLAS layout equivalence, operation flags, leading dimensions, beta = 1 accumulation, `CUDAGuard`/cuBLAS handle usage, and absence of ATen matrix multiply or handwritten kernels in the core computation.
- For a 3_sgemm-style candidate, specifically verify SGEMM1 opA=N/opB=N with A=X/B=W; SGEMM2 opA=N/opB=T with U shape {d,16}, m=d/n=16/k=d/ldc=d; and SGEMM3 opA=N/opB=N with m=d/n=d/k=16/beta=1.
- Prefer a minimal 3_sgemm-style hot path: no input checks, no `check_inputs`, no `TORCH_CHECK`, no input `.contiguous()` copies, `Y=empty_like(W)`, `U={d,16}`, current cuBLAS handle, no explicit `d >= 3584 && d <= 4608` check, direct `tensor.data_ptr<float>()` arguments inside `cublasSgemm`, and no explicit stream rebinding unless justified.

